/* global console, process */
import { spawn } from 'node:child_process';
import {
  existsSync,
  mkdirSync,
  mkdtempSync,
  readFileSync,
  renameSync,
  rmSync,
  statSync,
  writeFileSync,
} from 'node:fs';
import { tmpdir } from 'node:os';
import path from 'node:path';
import { performance } from 'node:perf_hooks';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const gnosisDir = path.resolve(__dirname, '../..');
const repoRoot = path.resolve(gnosisDir, '../..');
const workspaceBinDir = path.resolve(repoRoot, 'node_modules/.bin');
const invokeAppPath = path.resolve(__dirname, 'invoke-app.mjs');
const monsterPath = path.resolve(gnosisDir, 'polyglot/target/release/monster');
const gnexecCompatPath = path.resolve(gnosisDir, 'polyglot/target/release/gnexec');
const monsterRuntimePath = existsSync(monsterPath) ? monsterPath : gnexecCompatPath;
const monsterRuntimeName = existsSync(monsterPath) ? 'monster' : 'gnexec';
const aotCacheDir =
  process.env.MONSTER_TS_SHOOTOUT_AOT_CACHE_DIR ??
  path.join(tmpdir(), 'gnosis-monster-ts-aot-cache');

const examples = [
  {
    name: 'hello',
    kind: 'ts',
    sourcePath: path.resolve(__dirname, 'echo.ts'),
    compiledName: 'echo.js',
    inputJson: JSON.stringify({ name: 'gnode' }),
    expectedStdout: 'hello:gnode',
  },
  {
    name: 'fib(20)',
    kind: 'ts',
    sourcePath: path.resolve(__dirname, 'fib.ts'),
    compiledName: 'fib.js',
    inputJson: JSON.stringify({ n: 20 }),
    expectedStdout: '6765',
  },
  {
    name: 'fanout.gg',
    kind: 'gg',
    sourcePath: path.resolve(__dirname, 'fanout.gg'),
    inputJson: JSON.stringify({ userId: 'ada' }),
    expectedStdout: 'ada:user|ada:profile',
  },
];

function readNumberSetting(flagName, envName, fallback, legacyEnvName) {
  const rawFlag = process.argv
    .slice(2)
    .find((value) => value.startsWith(`--${flagName}=`));
  const rawEnvValue =
    process.env[envName] ??
    (legacyEnvName === undefined ? undefined : process.env[legacyEnvName]);
  const rawValue =
    rawFlag?.slice(flagName.length + 3) ??
    rawEnvValue ??
    `${fallback}`;
  const parsed = Number.parseInt(rawValue, 10);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

const warmupRuns = readNumberSetting(
  'warmup',
  'MONSTER_TS_SHOOTOUT_WARMUP',
  1,
  'GNEXEC_TS_SHOOTOUT_WARMUP'
);
const measuredRuns = readNumberSetting(
  'iterations',
  'MONSTER_TS_SHOOTOUT_ITERATIONS',
  5,
  'GNEXEC_TS_SHOOTOUT_ITERATIONS'
);

function percentile(sorted, ratio) {
  if (sorted.length === 0) {
    return 0;
  }

  const index = Math.min(
    sorted.length - 1,
    Math.max(0, Math.floor(sorted.length * ratio))
  );
  return sorted[index] ?? 0;
}

function summarize(samples) {
  const sorted = [...samples].sort((left, right) => left - right);
  const total = samples.reduce((sum, value) => sum + value, 0);
  return {
    meanMs: total / Math.max(1, samples.length),
    p50Ms: percentile(sorted, 0.5),
    p95Ms: percentile(sorted, 0.95),
    maxMs: sorted[sorted.length - 1] ?? 0,
  };
}

function flowPayloadForExample(example) {
  const parsed = JSON.parse(example.inputJson);
  if (typeof parsed.name === 'string') return parsed.name;
  if (typeof parsed.userId === 'string') return parsed.userId;
  if (typeof parsed.n === 'number') return String(parsed.n);
  return example.inputJson;
}

function encodeFlowFrame(payload, sequence) {
  const payloadBuffer = Buffer.from(payload, 'utf8');
  const header = Buffer.alloc(10);
  header.writeUInt16BE(1, 0);
  header.writeUInt32BE(sequence, 2);
  header[6] = 15;
  header[7] = (payloadBuffer.length >> 16) & 0xff;
  header[8] = (payloadBuffer.length >> 8) & 0xff;
  header[9] = payloadBuffer.length & 0xff;
  return Buffer.concat([header, payloadBuffer]);
}

function createResidentFlowRuntime(command, args, name) {
  const child = spawn(command, args, {
    cwd: gnosisDir,
    stdio: ['pipe', 'pipe', 'pipe'],
  });
  child.stdout.pause();
  let stderr = '';
  child.stderr.setEncoding('utf8');
  child.stderr.on('data', (chunk) => {
    stderr += chunk;
  });
  let sequence = 0;

  async function readExact(length) {
    const chunks = [];
    let total = 0;
    while (total < length) {
      const chunk = child.stdout.read(length - total);
      if (chunk !== null) {
        chunks.push(chunk);
        total += chunk.length;
        continue;
      }
      if (child.exitCode !== null) {
        throw new Error(`resident flow exited early: ${stderr}`);
      }
      await new Promise((resolve) => child.stdout.once('readable', resolve));
    }
    return Buffer.concat(chunks, total);
  }

  return {
    name,
    available: true,
    execute: async (example) => {
      sequence += 1;
      child.stdin.write(
        encodeFlowFrame(flowPayloadForExample(example), sequence)
      );
      try {
        const header = await readExact(10);
        const len = (header[7] << 16) | (header[8] << 8) | header[9];
        const payload = await readExact(len);
        return { exitCode: 0, stdout: `${payload.toString('utf8')}\n`, stderr };
      } catch (error) {
        return { exitCode: -1, stdout: '', stderr: String(error) };
      }
    },
    close: async () => {
      child.stdin.end();
      child.kill();
    },
  };
}

function stableHash64(value) {
  let hash = 0xcbf29ce484222325n;
  for (let index = 0; index < value.length; index += 1) {
    hash ^= BigInt(value.charCodeAt(index));
    hash = BigInt.asUintN(64, hash * 0x100000001b3n);
  }
  return hash.toString(16).padStart(16, '0');
}

async function runCommand(command, args, cwd, extraEnv = {}) {
  return await new Promise((resolve) => {
    const child = spawn(command, args, {
      cwd,
      env: { ...process.env, ...extraEnv },
      stdio: ['ignore', 'pipe', 'pipe'],
    });

    let stdout = '';
    let stderr = '';

    child.stdout.setEncoding('utf8');
    child.stderr.setEncoding('utf8');
    child.stdout.on('data', (chunk) => {
      stdout += chunk;
    });
    child.stderr.on('data', (chunk) => {
      stderr += chunk;
    });
    child.once('error', (error) => {
      resolve({
        exitCode: -1,
        stdout,
        stderr: String(error),
      });
    });
    child.once('close', (code) => {
      resolve({
        exitCode: code ?? -1,
        stdout,
        stderr,
      });
    });
  });
}

async function commandExists(command) {
  const result = await runCommand(
    'sh',
    ['-lc', `command -v ${command}`],
    repoRoot
  );
  return result.exitCode === 0;
}

async function compileNodeFixtures(outputDir) {
  const result = await runCommand(
    path.resolve(workspaceBinDir, 'tsc'),
    [
      '--target',
      'es2022',
      '--module',
      'nodenext',
      '--moduleResolution',
      'nodenext',
      '--types',
      'node',
      '--skipLibCheck',
      '--outDir',
      outputDir,
      ...examples
        .filter((example) => example.kind === 'ts')
        .map((example) => example.sourcePath),
    ],
    repoRoot
  );

  if (result.exitCode !== 0) {
    throw new Error(
      `Failed to compile Node fixtures:\n${result.stderr || result.stdout}`
    );
  }
}

async function measureRuntime(runtime, example) {
  for (let run = 0; run < warmupRuns; run += 1) {
    const warmup = await runtime.execute(example);
    if (warmup.exitCode !== 0) {
      throw new Error(
        `${runtime.name} failed warmup for ${example.name}:\n${warmup.stderr}`
      );
    }
    if (warmup.stdout.trim() !== example.expectedStdout) {
      throw new Error(
        `${runtime.name} produced unexpected output for ${
          example.name
        }: '${warmup.stdout.trim()}'`
      );
    }
  }

  const samples = [];
  for (let run = 0; run < measuredRuns; run += 1) {
    const started = performance.now();
    const result = await runtime.execute(example);
    const elapsedMs = performance.now() - started;
    if (result.exitCode !== 0) {
      throw new Error(
        `${runtime.name} failed for ${example.name}:\n${result.stderr}`
      );
    }
    if (result.stdout.trim() !== example.expectedStdout) {
      throw new Error(
        `${runtime.name} produced unexpected output for ${
          example.name
        }: '${result.stdout.trim()}'`
      );
    }
    samples.push(elapsedMs);
  }

  return summarize(samples);
}

function printSummary(exampleName, rows) {
  console.log(`\n${exampleName}`);
  for (const row of rows) {
    if ('skipped' in row) {
      console.log(`${row.name.padEnd(8)} | skipped=${row.skipped}`);
      continue;
    }
    const setup = row.setup
      ? [
          row.setup.cacheHit === undefined
            ? ''
            : ` | cache=${row.setup.cacheHit ? 'hit' : 'miss'}`,
          row.setup.generationMs === undefined
            ? ''
            : ` | gen=${row.setup.generationMs.toFixed(2)}ms`,
          row.setup.compileMs === undefined
            ? ''
            : ` | cc=${row.setup.compileMs.toFixed(2)}ms`,
        ].join('')
      : '';
    console.log(
      [
        row.name.padEnd(8),
        `mean=${row.summary.meanMs.toFixed(2)}ms`,
        `p50=${row.summary.p50Ms.toFixed(2)}ms`,
        `p95=${row.summary.p95Ms.toFixed(2)}ms`,
        `max=${row.summary.maxMs.toFixed(2)}ms`,
      ].join(' | ') + setup
    );
  }

  const monster = rows.find(
    (row) => row.name === monsterRuntimeName && !('skipped' in row)
  );
  const rustOptout = rows.find(
    (row) => row.name === 'monster-rust-optout' && !('skipped' in row)
  );
  if (monster && rustOptout) {
    const savedMs = rustOptout.summary.meanMs - monster.summary.meanMs;
    const decision = savedMs > 0 ? 'resident-flow-default' : 'inspect-regression';
    console.log(
      [
        'decision'.padEnd(8),
        `saved=${savedMs.toFixed(2)}ms/request`,
        decision,
      ].join(' | ')
    );
  }
}

async function prepareMonsterCAot(example, outputDir) {
  const cPath = path.join(outputDir, `${example.name.replace(/[^a-z0-9]/gi, '-')}.c`);
  const binaryPath = path.join(
    outputDir,
    `${example.name.replace(/[^a-z0-9]/gi, '-')}-monster-c-aot`
  );

  const generationStarted = performance.now();
  const generated = await runCommand(
    monsterRuntimePath,
    [
      example.sourcePath,
      '--export',
      'app',
      '--emit-c',
      '--unstable-aot-c',
    ],
    gnosisDir
  );
  const generationMs = performance.now() - generationStarted;
  if (generated.exitCode !== 0) {
    return {
      skipped: generated.stderr.trim() || generated.stdout.trim() || 'C emission failed',
    };
  }
  writeFileSync(cPath, generated.stdout);

  const compileStarted = performance.now();
  const compiled = await runCommand(
    'cc',
    ['-O3', '-march=native', cPath, '-lm', '-o', binaryPath],
    repoRoot
  );
  const compileMs = performance.now() - compileStarted;
  if (compiled.exitCode !== 0) {
    return {
      skipped: compiled.stderr.trim() || compiled.stdout.trim() || 'C compilation failed',
    };
  }

  return {
    runtime: {
      name: 'monster-c-aot',
      available: true,
      setup: { generationMs, compileMs },
      execute: async (fixture) =>
        await runCommand(binaryPath, [fixture.inputJson], repoRoot),
    },
  };
}

function aotCacheKey(example) {
  const source = readFileSync(example.sourcePath, 'utf8');
  const runtimeStats = statSync(monsterRuntimePath);
  return stableHash64(
    JSON.stringify({
      schema: 'monster-ts-shootout-aot-c-v1',
      fixture: example.name,
      kind: example.kind,
      exportName: 'app',
      source,
      runtime: {
        name: monsterRuntimeName,
        size: runtimeStats.size,
        mtimeMs: Math.trunc(runtimeStats.mtimeMs),
      },
    })
  );
}

async function prepareMonsterCAotReusable(example) {
  mkdirSync(aotCacheDir, { recursive: true });
  const key = aotCacheKey(example);
  const safeName = example.name.replace(/[^a-z0-9]/gi, '-');
  const cPath = path.join(aotCacheDir, `${safeName}-${key}.c`);
  const binaryPath = path.join(aotCacheDir, `${safeName}-${key}.bin`);
  const metaPath = path.join(aotCacheDir, `${safeName}-${key}.json`);

  if (existsSync(binaryPath)) {
    return {
      runtime: {
        name: 'monster-c-reuse',
        available: true,
        setup: { cacheHit: true },
        binaryPath,
        execute: async (fixture) =>
          await runCommand(binaryPath, [fixture.inputJson], repoRoot),
      },
    };
  }

  const generationStarted = performance.now();
  const generated = await runCommand(
    monsterRuntimePath,
    [
      example.sourcePath,
      '--export',
      'app',
      '--emit-c',
      '--unstable-aot-c',
    ],
    gnosisDir
  );
  const generationMs = performance.now() - generationStarted;
  if (generated.exitCode !== 0) {
    return {
      skipped:
        generated.stderr.trim() || generated.stdout.trim() || 'C emission failed',
    };
  }
  writeFileSync(cPath, generated.stdout);

  const temporaryBinaryPath = `${binaryPath}.tmp`;
  const compileStarted = performance.now();
  const compiled = await runCommand(
    'cc',
    ['-O3', '-march=native', cPath, '-lm', '-o', temporaryBinaryPath],
    repoRoot
  );
  const compileMs = performance.now() - compileStarted;
  if (compiled.exitCode !== 0) {
    return {
      skipped:
        compiled.stderr.trim() || compiled.stdout.trim() || 'C compilation failed',
    };
  }
  rmSync(binaryPath, { force: true });
  writeFileSync(
    metaPath,
    `${JSON.stringify(
      {
        key,
        fixture: example.name,
        sourcePath: example.sourcePath,
        cPath,
        binaryPath,
        generatedAt: new Date().toISOString(),
      },
      null,
      2
    )}\n`
  );
  renameSync(temporaryBinaryPath, binaryPath);

  return {
    runtime: {
      name: 'monster-c-reuse',
      available: true,
      setup: { cacheHit: false, generationMs, compileMs },
      binaryPath,
      execute: async (fixture) =>
        await runCommand(binaryPath, [fixture.inputJson], repoRoot),
    },
  };
}

async function main() {
  if (!existsSync(monsterRuntimePath)) {
    throw new Error(
      `Missing ${monsterRuntimePath}; run cargo --manifest-path polyglot/Cargo.toml build --release --bin monster first.`
    );
  }

  const compiledOutputDir = mkdtempSync(
    path.join(tmpdir(), 'monster-ts-shootout-')
  );

  try {
    const nodeCompilerAvailable = existsSync(path.resolve(workspaceBinDir, 'tsc'));
    if (nodeCompilerAvailable) {
      await compileNodeFixtures(compiledOutputDir);
    }

    const runtimes = [
      {
        name: `${monsterRuntimeName}-process`,
        available: true,
        execute: async (example) =>
          await runCommand(
            monsterRuntimePath,
            [
              example.sourcePath,
              '--input-json',
              example.inputJson,
              '--export',
              'app',
            ],
            gnosisDir
          ),
      },
      {
        name: 'monster-rust-optout',
        available: true,
        execute: async (example) =>
          await runCommand(
            monsterRuntimePath,
            [
              example.sourcePath,
              '--input-json',
              example.inputJson,
              '--export',
              'app',
              '--no-aot-c',
            ],
            gnosisDir
          ),
      },
      {
        name: 'bun',
        available: await commandExists('bun'),
        supports: (example) => example.kind === 'ts',
        execute: async (example) =>
          await runCommand(
            'bun',
            [invokeAppPath, example.sourcePath, example.inputJson],
            repoRoot
          ),
      },
      {
        name: 'node',
        available: nodeCompilerAvailable && (await commandExists('node')),
        supports: (example) => example.kind === 'ts',
        unavailableReason: nodeCompilerAvailable
          ? 'command not found'
          : 'workspace tsc not found',
        execute: async (example) =>
          await runCommand(
            'node',
            [
              invokeAppPath,
              path.join(compiledOutputDir, example.compiledName),
              example.inputJson,
            ],
            repoRoot
          ),
      },
      {
        name: 'deno',
        available: false, // disabled: tsconfig jsx conflict
        supports: (example) => example.kind === 'ts',
        execute: async (example) =>
          await runCommand(
            'deno',
            [
              'run',
              '--quiet',
              '--allow-read',
              invokeAppPath,
              example.sourcePath,
              example.inputJson,
            ],
            repoRoot
          ),
      },
    ];

    console.log('monster TypeScript runtime shootout');
    console.log(`warmup=${warmupRuns} measured=${measuredRuns}`);

    for (const example of examples) {
      const monsterCAot = (await commandExists('cc'))
        ? await prepareMonsterCAot(example, compiledOutputDir)
        : { skipped: 'cc command not found' };
      const monsterCReuse = (await commandExists('cc'))
        ? await prepareMonsterCAotReusable(example)
        : { skipped: 'cc command not found' };
      const rows = [];
      const exampleRuntimes = [
        createResidentFlowRuntime(
          monsterRuntimePath,
          [example.sourcePath, '--export', 'app', '--resident-flow-stdio'],
          monsterRuntimeName
        ),
        ...runtimes,
      ];
      if ('runtime' in monsterCAot) {
        exampleRuntimes.push(monsterCAot.runtime);
      } else {
        rows.push({ name: 'monster-c-aot', skipped: monsterCAot.skipped });
      }
      if ('runtime' in monsterCReuse) {
        exampleRuntimes.push(monsterCReuse.runtime);
        exampleRuntimes.push(
          createResidentFlowRuntime(
            monsterCReuse.runtime.binaryPath,
            ['--resident-flow-stdio'],
            'monster-c-flow'
          )
        );
      } else {
        rows.push({ name: 'monster-c-reuse', skipped: monsterCReuse.skipped });
        rows.push({ name: 'monster-c-flow', skipped: monsterCReuse.skipped });
      }
      exampleRuntimes.push({
        name: 'monster-c-cache',
        available: true,
        execute: async (fixture) =>
          await runCommand(
            monsterRuntimePath,
            [
              fixture.sourcePath,
              '--input-json',
              fixture.inputJson,
              '--export',
              'app',
              '--aot-cached',
              '--unstable-aot-c',
            ],
            gnosisDir
          ),
      });
      for (const runtime of exampleRuntimes) {
        if (runtime.supports && !runtime.supports(example)) {
          rows.push({
            name: runtime.name,
            skipped: `unsupported ${example.kind} fixture`,
          });
          continue;
        }
        if (!runtime.available) {
          rows.push({
            name: runtime.name,
            skipped: runtime.unavailableReason ?? 'command not found',
          });
          continue;
        }
        const summary = await measureRuntime(runtime, example);
        rows.push({
          name: runtime.name,
          summary,
          setup: runtime.setup,
        });
        if (typeof runtime.close === 'function') {
          await runtime.close();
        }
      }
      rows.sort((left, right) => {
        if ('skipped' in left) {
          return 1;
        }
        if ('skipped' in right) {
          return -1;
        }
        return left.summary.meanMs - right.summary.meanMs;
      });
      printSummary(example.name, rows);
    }
  } finally {
    rmSync(compiledOutputDir, { recursive: true, force: true });
  }
}

main().catch((error) => {
  const message =
    error instanceof Error ? error.stack ?? error.message : String(error);
  process.stderr.write(`${message}\n`);
  process.exitCode = 1;
});
